# Activity rates (USD per 1,000 calls) — calibrated quarterly from actual cost data
ACTIVITY_RATES: dict[str, float] = {
    "summarisation":    0.18,   # moderate output length
    "classification":   0.04,   # short output
    "code-generation":  0.55,   # long output, complex context
    "chat":             0.22,   # varies; use rolling 30-day avg
    "document-qa":      0.30,   # large input context typical
}

def activity_based_report(ledger_df: pd.DataFrame) -> pd.DataFrame:
    """Charge teams by activity type × call count using per-activity rates."""
    call_counts = (
        ledger_df.groupby(["team", "cost_center", "use_case"])
        .agg(calls=("call_id", "count"))
        .reset_index()
    )
    call_counts["rate_per_1k"] = call_counts["use_case"].map(ACTIVITY_RATES).fillna(0.20)
    call_counts["allocated_cost_usd"] = (
        call_counts["calls"] / 1000 * call_counts["rate_per_1k"]
    ).round(4)
    return call_counts.sort_values("allocated_cost_usd", ascending=False)

REQUIRED_TAGS = {"team", "use_case", "cost_center", "environment"}
VALID_ENVIRONMENTS = {"production", "staging", "development", "experiment"}
VALID_USE_CASES = {
    "summarisation", "classification", "code-generation",
    "chat", "document-qa", "translation", "extraction",
}

class TagValidator:
    def validate(self, tags: dict) -> list[str]:
        """Return list of validation errors; empty list means valid."""
        errors = []
        missing = REQUIRED_TAGS - set(tags.keys())
        if missing:
            errors.append(f"Missing required tags: {sorted(missing)}")
        env = tags.get("environment", "")
        if env and env not in VALID_ENVIRONMENTS:
            errors.append(f"Invalid environment '{env}'. Valid: {sorted(VALID_ENVIRONMENTS)}")
        uc = tags.get("use_case", "")
        if uc and uc not in VALID_USE_CASES:
            errors.append(f"Invalid use_case '{uc}'. Valid: {sorted(VALID_USE_CASES)}")
        cc = tags.get("cost_center", "")
        if cc and not cc.startswith("CC-"):
            errors.append(f"cost_center must start with 'CC-', got '{cc}'")
        return errors

# Integrate into the instrumentation wrapper:
validator = TagValidator()
errors = validator.validate(tags)
if errors:
    if tags.get("environment") == "production":
        raise ValueError(f"Tag validation failed: {errors}")
    else:
        import warnings
        warnings.warn(f"Tag validation warnings: {errors}")

def tag_compliance_report(ledger_df, period: str) -> dict:
    """Summarise tagging completeness for the FinOps governance dashboard."""
    total_calls = len(ledger_df)
    total_cost = ledger_df["cost_usd"].sum()

    results = {}
    for tag in ["team", "use_case", "cost_center", "environment"]:
        tagged = ledger_df[tag].notna() & (ledger_df[tag] != "")
        results[tag] = {
            "tagged_calls": int(tagged.sum()),
            "tagged_pct": round(tagged.mean() * 100, 1),
            "untagged_cost_usd": round(ledger_df.loc[~tagged, "cost_usd"].sum(), 4),
        }

    return {
        "period": period,
        "total_calls": total_calls,
        "total_cost_usd": round(total_cost, 4),
        "tag_compliance": results,
        "untagged_cost_pct": round(
            ledger_df.loc[ledger_df["cost_center"].isna(), "cost_usd"].sum()
            / total_cost * 100, 1
        ) if total_cost > 0 else 0.0,
    }
